type IgnitionModuleResultsTToEthersContracts<
  ContractNameT extends string,
  IgnitionModuleResultsT extends IgnitionModuleResult<ContractNameT>,
> = {
  [contract in keyof IgnitionModuleResultsT]: IgnitionModuleResultsT[contract] extends
    | NamedArtifactContractDeploymentFuture<ContractNameT>
    | NamedArtifactContractAtFuture<ContractNameT>
    ? TypeChainEthersContractByName<ContractNameT>
    : Contract;
};

interface BaseExecutionState<
  ExecutionStateT extends ExecutionSateType,
  FutureTypeT extends FutureType,
> {
  id: string;
  type: ExecutionStateT;
  futureType: FutureTypeT;
  strategy: string; // For example, "basic" | "create2". This needs to be string if we want custom ones.
  strategyConfig: ConcreteExecutionConfig;
  status: ExecutionStatus;
  dependencies: Set<string>;
}

interface ContractAtExecutionStateInitializeMessage {
  type: JournalMessageType.CONTRACT_AT_EXECUTION_STATE_INITIALIZE;
  futureType: FutureType.NAMED_ARTIFACT_CONTRACT_AT | FutureType.CONTRACT_AT;
  futureId: string;
  strategy: string;
  strategyConfig: ConcreteExecutionConfig;
  dependencies: string[];
  artifactId: string;
  contractName: string;
  contractAddress: string;
}

interface ReadEventArgExecutionStateInitializeMessage {
  type: JournalMessageType.READ_EVENT_ARGUMENT_EXECUTION_STATE_INITIALIZE;
  futureId: string;
  strategy: string;
  strategyConfig: ConcreteExecutionConfig;
  dependencies: string[];
  artifactId: string;
  eventName: string;
  nameOrIndex: string | number;
  txToReadFrom: string;
  emitterAddress: string;
  eventIndex: number;
  result: SolidityParameterType;
}

interface ContractDeploymentFuture<AbiT extends Abi = Abi> {
  type: FutureType.CONTRACT_DEPLOYMENT;
  id: string;
  module: IgnitionModule;
  dependencies: Set<Future | IgnitionModule>;
  contractName: string;
  artifact: Artifact<AbiT>;
  constructorArgs: ArgumentType[];
  libraries: Record<string, ContractFuture<string>>;
  value:
    | bigint
    | ModuleParameterRuntimeValue<bigint>
    | StaticCallFuture<string, string>
    | ReadEventArgumentFuture;
  from: string | AccountRuntimeValue | undefined;
}

interface NamedArtifactLibraryDeploymentFuture<
  LibraryNameT extends string,
> {
  type: FutureType.NAMED_ARTIFACT_LIBRARY_DEPLOYMENT;
  id: string;
  module: IgnitionModule;
  dependencies: Set<Future | IgnitionModule>;
  contractName: LibraryNameT;
  libraries: Record<string, ContractFuture<string>>;
  from: string | AccountRuntimeValue | undefined;
}

interface SerializedNamedContractDeploymentFuture
  extends BaseSerializedFuture {
  type: FutureType.NAMED_ARTIFACT_CONTRACT_DEPLOYMENT;
  contractName: string;
  constructorArgs: SerializedArgumentType[];
  libraries: SerializedLibraries;
  value: SerializedBigInt | SerializedModuleParameterRuntimeValue | FutureToken;
  from: string | SerializedAccountRuntimeValue | undefined;
}

interface SerializedArtifactContractDeploymentFuture
  extends BaseSerializedFuture {
  type: FutureType.CONTRACT_DEPLOYMENT;
  contractName: string;
  constructorArgs: SerializedArgumentType[];
  artifact: Artifact;
  libraries: SerializedLibraries;
  value: SerializedBigInt | SerializedModuleParameterRuntimeValue | FutureToken;
  from: string | SerializedAccountRuntimeValue | undefined;
}

interface SerializedSendDataFuture extends BaseSerializedFuture {
  type: FutureType.SEND_DATA;
  to:
    | string
    | FutureToken
    | SerializedModuleParameterRuntimeValue
    | SerializedAccountRuntimeValue;
  value: SerializedBigInt | SerializedModuleParameterRuntimeValue;
  data: string | FutureToken | undefined;
  from: string | SerializedAccountRuntimeValue | undefined;
}

const handlers: Partial<ConfigHooks> = {
  validateUserConfig: async (userConfig) =>
    await validateLedgerUserConfig(userConfig),
  resolveUserConfig: async (
    userConfig,
    resolveConfigurationVariable,
    next,
  ) => {
    const resolvedConfig = await next(
      userConfig,
      resolveConfigurationVariable,
    );

    return resolveLedgerUserConfig(userConfig, resolvedConfig);
  },
};

