if (
  // The "item.name" must match the name of the variable where the OutputTransformer is defined, which in this case is "compiledFilesTransformer"
  outputTransformers.some((item) => item.name === "compiledFilesTransformer")
) {
  // Check if the `compiledFilesTransformer` output transformer is present. If multiple contracts are compiled at different
  // times in the same process, the `compiledFilesTransformer` transformer may have already been added earlier.
  return;
}

class UnnecessaryLibraryError extends CustomError {
  constructor(libraries: string[]) {
    const formattedLibraries = libraries
      .map((libraryName) => `\t* "${libraryName}"`)
      .join("\n");

    super(`The following libraries are not referenced by the contract:
${formattedLibraries}

Please provide only the libraries that are needed.`);
  }
}

class OverlappingLibrariesError extends CustomError {
  constructor(libraries: string[]) {
    const formattedLibraries = libraries
      .map((libraryFqn) => `\t* "${libraryFqn}"`)
      .join("\n");

    super(`The following libraries are provided more than once:
${formattedLibraries}

Please ensure that each library is provided only once, either by its name or its fully qualified name.`);
  }
}

