const handlers: Partial<NetworkHooks> = {
  async newConnection<ChainTypeT extends ChainType | string>(
    context: HookContext,
    next: (
      nextContext: HookContext,
    ) => Promise<NetworkConnection<ChainTypeT>>,
  ) {
    const connection = await next(context);

    connection.viem.assertions = await initializeViemAssertions(
      connection.viem,
    );

    return connection;
  },
};

try {
  const hardhatMetadata = await provider.request({
    method: HARDHAT_METADATA_METHOD,
  });

  assertHardhatInvariant(
    isHardhatMetadata(hardhatMetadata),
    "Expected valid hardhat metadata response",
  );

  hardhatMetadataCache.set(provider, hardhatMetadata);
  return true;
} catch {
  hardhatMetadataCache.delete(provider);
  return false;
}

const edrNetworkMiningUserConfigSchema = z.object({
  auto: z.optional(z.boolean()),
  interval: z.optional(
    unionType(
      [
        nonnegativeIntSchema,
        z.tuple([nonnegativeIntSchema, nonnegativeIntSchema]),
      ],
      "Expected a number or an array of numbers",
    ),
  ),
  mempool: z.optional(edrNetworkMempoolUserConfigSchema),
});

const userConfigSchema = z
  .object({
    chainDescriptors: z.optional(chainDescriptorsUserConfigSchema),
    defaultChainType: z.optional(chainTypeUserConfigSchema),
    networks: z.optional(z.record(networkUserConfigSchema)),
  })
  // The superRefine is used to perform additional validation of correlated
  // fields of the edr network that are not possible to express with Zod's
  // built-in validation methods. It is applied to the whole user config object
  // because we need access to the defaultChainType.
  .superRefine(refineEdrNetworkUserConfig);

if (!preferWasm) {
  const platform = CompilerDownloaderImplementation.getCompilerPlatform();

  if (hasNativeBuildForPlatform(version, platform)) {
    const compilerDownloader = new CompilerDownloaderImplementation(
      platform,
      await getGlobalCompilersCacheDir(),
    );

    const compiler = await compilerDownloader.getCompiler(version);

    if (compiler !== undefined) {
      return compiler;
    }
  }
}

